"use strict";

import Fuse from "https://cdn.jsdelivr.net/npm/fuse.js@7.4/+esm";

let fuseIndex;
let exactFuseIndex;
let phraseFuseIndex;
let searchData;

// See: https://www.fusejs.io/api/options.html
const fuseOptions = {
  threshold: 0.4,
  ignoreLocation: true,
  useExtendedSearch: true,
  useTokenSearch: true,

  minMatchCharLength: 1,
  // findAllMatches: true,
  shouldSort: true,
  includeScore: true,

  keys: [
    { name: "href",     weight: 0.5 },
    { name: "title",    weight: 0.8 },
    { name: "keywords", weight: 0.7 },
    { name: "summary", weight: 0.3 }
  ]
};

onmessage = oEvent => {
  const q = oEvent.data.q;
  let results = [];
  if (fuseIndex && searchData) {
    let hits = [];
    // -------------------------------------------------------------------------
    // Custom Parsing for Extended Search Operators on Phrases
    // -------------------------------------------------------------------------
    // Native Fuse.js extended search (when `useTokenSearch` is true) splits 
    // quoted phrases by space, which breaks the ability to search for exact 
    // multi-word phrases alongside other operators.
    // To solve this, we manually parse the query to extract quoted phrases,
    // their optional operator prefixes (!, ^, =, etc.), and standard tokens.
    // We then evaluate each phrase or token against a specialized Fuse index
    // and manually intersect the results to build the final response.
    //
    // Regex Groups:
    // 1: Optional operator prefix (e.g., !^, !$, !, ^, =, ')
    // 2: The quoted phrase content
    // 3: Optional operator suffix (e.g., $)
    // 4: Standard unquoted token
    // -------------------------------------------------------------------------
    const queryParserRegex = /(?:(!\^|!\$|!|\^|=|')?"([^"]+)"(\$?))|([^\s]+)/g;
    let matches = [];
    let match;
    while ((match = queryParserRegex.exec(q)) !== null) {
      if (match[2]) {
        matches.push({ type: 'phrase', opPrefix: match[1] || '', value: match[2], opSuffix: match[3] || '' });
      } else if (match[4]) {
        matches.push({ type: 'normal', value: match[4] });
      }
    }

    if (matches.length === 0) {
      hits = [];
    } else {
      let normalTokens = matches.filter(m => m.type === 'normal').map(m => m.value).join(' ');
      let phraseTokens = matches.filter(m => m.type === 'phrase');
      let resultSets = [];
      let isInverseSet = [];

      if (normalTokens) {
        resultSets.push(fuseIndex.search(normalTokens));
        isInverseSet.push(false);
      }

      for (let m of phraseTokens) {
        let op = m.opPrefix;
        let termHits = [];
        let isInverse = false;

        if (op === '=') {
          termHits = exactFuseIndex.search(m.value);
        } else if (op === '!') {
          termHits = phraseFuseIndex.search(m.value);
          isInverse = true;
        } else if (op === '^' || op === '!^' || op === '!$' || op === "'") {
          termHits = phraseFuseIndex.search(m.value);
          if (op === '!^' || op === '!$') isInverse = true;
        } else {
          termHits = phraseFuseIndex.search(m.value);
        }
        
        resultSets.push(termHits);
        isInverseSet.push(isInverse);
      }

      if (resultSets.length > 0) {
        let intersectedMap = new Map();
        
        if (isInverseSet[0]) {
            let hitHrefs = new Set(resultSets[0].map(h => h.item.href));
            for (let item of searchData) {
                if (!hitHrefs.has(item.href)) {
                    intersectedMap.set(item.href, { hit: { item, score: 1 }, score: 1 });
                }
            }
        } else {
            for (let hit of resultSets[0]) {
                intersectedMap.set(hit.item.href, { hit, score: hit.score || 0 });
            }
        }

        for (let i = 1; i < resultSets.length; i++) {
          let currentSet = resultSets[i];
          let isInverse = isInverseSet[i];
          let nextMap = new Map();
          
          if (isInverse) {
              let hitHrefs = new Set(currentSet.map(h => h.item.href));
              for (let [href, prev] of intersectedMap.entries()) {
                  if (!hitHrefs.has(href)) {
                      nextMap.set(href, { hit: prev.hit, score: prev.score + 1 });
                  }
              }
          } else {
              for (let hit of currentSet) {
                if (intersectedMap.has(hit.item.href)) {
                  let prev = intersectedMap.get(hit.item.href);
                  nextMap.set(hit.item.href, { hit: prev.hit, score: prev.score + (hit.score || 0) });
                }
              }
          }
          intersectedMap = nextMap;
        }
        hits = Array.from(intersectedMap.values()).sort((a, b) => a.score - b.score).map(x => x.hit);
      }
    }

    results = hits.map((hit) => {
      const item = hit.item;
      return {
        href: item.href,
        title: item.title,
        keywords: item.keywords,
        summary: item.summary
      };
    });
  }
  postMessage({ e: "query-ready", q, d: results });
}

async function buildIndex() {
  const response = await fetch("../index.json");
  if (!response.ok) return;

  const json = await response.json();
  searchData = Object.values(json);
  if (searchData && searchData.length > 0) {
    fuseIndex = new Fuse(searchData, fuseOptions);
    exactFuseIndex = new Fuse(searchData, Object.assign({}, fuseOptions, { threshold: 0.0, useExtendedSearch: false, useTokenSearch: false }));
    phraseFuseIndex = new Fuse(searchData, Object.assign({}, fuseOptions, { useExtendedSearch: false, useTokenSearch: false }));
  }
  postMessage({ e: "index-ready" });
}

await buildIndex();
